UPDATE SRBA_VALT_SCHD_M
SET ING_STEP = #{ingStep}
WHERE BAS_YYMM = #{basYymm}

mapper.select:
	SELECT (CASE WHEN RSK_CNT > 0 AND CNT = 0 THEN 'Y'
                 ELSE 'N' END ) RUSTL  
      FROM (SELECT COUNT(*) RSK_CNT
              FROM SRBA_V_RSK_R 
             WHERE 1=1
               AND BAS_YYMM = #{basYymm}
           ) M
          ,(SELECT COUNT(*) CNT
              FROM SRBA_V_MLTF_CUST_I
             WHERE 1=1
               AND BAS_YYMM = #{basYymm}
           ) A
